def {{nama_fungsi}}(path, algo='sha256'):
    """Return hex digest."""
    import hashlib
    h = hashlib.new(algo)
    with open(path, 'rb') as f:
        for chunk in iter(lambda: f.read(8192), b''):
            h.update(chunk)
    return h.hexdigest()

def {{nama_fungsi}}(length={{length}}, alphabet=None):
    """Secure random string."""
    import secrets, string
    if alphabet is None:
        alphabet = string.ascii_letters + string.digits
    return ''.join(secrets.choice(alphabet) for _ in range(length))

def {{nama_fungsi}}(password):
    """Return {'score':0-5, 'feedback': [...]}."""
    import re
    score = 0
    feedback = []
    if len(password) >= 8: score += 1
    else: feedback.append("Minimal 8 karakter")
    if re.search(r'[a-z]', password): score += 1
    else: feedback.append("Tambah huruf kecil")
    if re.search(r'[A-Z]', password): score += 1
    else: feedback.append("Tambah huruf besar")
    if re.search(r'\d', password): score += 1
    else: feedback.append("Tambah angka")
    if re.search(r'[^a-zA-Z0-9]', password): score += 1
    else: feedback.append("Tambah simbol")
    return {'score': score, 'feedback': feedback, 'strong': score >= 4}

def {{nama_fungsi}}_sign(message, key):
    """Return hex HMAC-SHA256."""
    import hmac, hashlib
    if isinstance(key, str): key = key.encode()
    if isinstance(message, str): message = message.encode()
    return hmac.new(key, message, hashlib.sha256).hexdigest()

def {{nama_fungsi}}_verify(message, key, signature):
    import hmac
    expected = {{nama_fungsi}}_sign(message, key)
    return hmac.compare_digest(expected, signature)

def {{nama_fungsi}}(html, allowed_tags=None):
    """Strip tag berbahaya. Very simple."""
    import re
    from html.parser import HTMLParser
    if allowed_tags is None:
        allowed_tags = {'b','i','u','em','strong','p','br','ul','ol','li'}
    class Sanitizer(HTMLParser):
        def __init__(self):
            super().__init__()
            self.out = []
        def handle_starttag(self, tag, attrs):
            if tag.lower() in allowed_tags:
                self.out.append(f"<{tag}>")
        def handle_endtag(self, tag):
            if tag.lower() in allowed_tags:
                self.out.append(f"</{tag}>")
        def handle_data(self, data):
            self.out.append(data)
    s = Sanitizer()
    s.feed(html)
    return ''.join(s.out)

def {{nama_fungsi}}(text, mode='html'):
    """mode: html, sql, shell."""
    if mode == 'html':
        import html
        return html.escape(text)
    elif mode == 'sql':
        return text.replace("'", "''")
    elif mode == 'shell':
        import shlex
        return shlex.quote(text)
    return text

def {{nama_fungsi}}_encode(payload, secret):
    """Encode JWT HS256."""
    import json, base64, hmac, hashlib
    def b64u(b):
        return base64.urlsafe_b64encode(b).rstrip(b'=').decode()
    header = {'alg': 'HS256', 'typ': 'JWT'}
    h_b = b64u(json.dumps(header, separators=(',', ':')).encode())
    p_b = b64u(json.dumps(payload, separators=(',', ':')).encode())
    signing = f"{h_b}.{p_b}".encode()
    sig = hmac.new(secret.encode() if isinstance(secret, str) else secret, signing, hashlib.sha256).digest()
    s_b = b64u(sig)
    return f"{h_b}.{p_b}.{s_b}"

def {{nama_fungsi}}_decode(token, secret, verify=True):
    import json, base64, hmac, hashlib
    def b64u_decode(s):
        s += '=' * (-len(s) % 4)
        return base64.urlsafe_b64decode(s)
    try:
        h_b, p_b, s_b = token.split('.')
    except ValueError:
        raise ValueError("Invalid token")
    if verify:
        signing = f"{h_b}.{p_b}".encode()
        sig = b64u_decode(s_b)
        expected = hmac.new(secret.encode() if isinstance(secret, str) else secret, signing, hashlib.sha256).digest()
        if not hmac.compare_digest(sig, expected):
            raise ValueError("Invalid signature")
    payload = json.loads(b64u_decode(p_b))
    return payload
